import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { QRCodeSVG } from 'qrcode.react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import Scanner from './Scanner';
import './App.css';

function App() {
  const [products, setProducts] = useState([]);
  const [showScanner, setShowScanner] = useState(false);

  useEffect(() => { fetchProducts(); }, []);

  const fetchProducts = async () => {
    const res = await axios.get('http://127.0.0.1:8000/api/products/');
    setProducts(res.data);
  };

  const updateStock = async (id, newQuantity) => {
    if (newQuantity < 0) return;
    await axios.patch(`http://127.0.0.1:8000/api/products/${id}/`, { quantity: newQuantity });
    fetchProducts();
  };

  const handleScan = (sku) => {
    const product = products.find(p => p.sku === sku.trim());
    if (product) {
      updateStock(product.id, product.quantity + 1);
      alert(`Updated ${product.name}`);
      setShowScanner(false);
    } else {
      alert("SKU not found");
    }
  };

  // Logic for Dashboard
  const lowStockItems = products.filter(p => p.quantity < 10);
  const totalValue = products.reduce((acc, p) => acc + (p.price * p.quantity), 0);

  return (
    <div className="App">
      <header className="dashboard-header">
        <h1>Smart Warehouse AI</h1>
        <div className="stats-container">
          <div className="stat-card">
            <h3>Total Value</h3>
            <p className="stat-value">${totalValue.toLocaleString()}</p>
          </div>
          <div className="stat-card">
            <h3>Alerts</h3>
            <p className="stat-value" style={{color: '#ff3860'}}>{lowStockItems.length}</p>
          </div>
        </div>
      </header>

      <section className="analytics-section">
        <h2>Stock Levels (Visual)</h2>
        <div style={{ width: '100%', height: 300 }}>
          <ResponsiveContainer>
            <BarChart data={products}>
              <XAxis dataKey="name" stroke="#fff" />
              <YAxis stroke="#fff" />
              <Tooltip contentStyle={{backgroundColor: '#333', border: 'none'}} />
              <Bar dataKey="quantity">
                {products.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.quantity < 10 ? '#ff3860' : '#00d1b2'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </section>

      <div className="action-bar">
        <button className="scan-btn" onClick={() => setShowScanner(!showScanner)}>
          {showScanner ? "Close Camera" : "📸 Scan Inbound Stock"}
        </button>
      </div>

      {showScanner && <Scanner onScanSuccess={handleScan} />}

      <div className="inventory-list">
        <h2>Live Inventory Table</h2>
        <table>
          <thead>
            <tr>
              <th>SKU</th>
              <th>Product</th>
              <th>Quantity</th>
              <th>Status</th>
              <th>QR</th>
              <th>Adjust</th>
            </tr>
          </thead>
          <tbody>
            {products.map(p => (
              <tr key={p.id}>
                <td><code>{p.sku}</code></td>
                <td>{p.name}</td>
                <td>{p.quantity}</td>
                <td>
                  <span className={`status-pill ${p.quantity < 10 ? 'critical' : 'healthy'}`}>
                    {p.quantity < 10 ? 'Restock' : 'OK'}
                  </span>
                </td>
                <td><QRCodeSVG value={p.sku} size={40} /></td>
                <td>
                  <button onClick={() => updateStock(p.id, p.quantity + 1)}>+</button>
                  <button onClick={() => updateStock(p.id, p.quantity - 1)}>-</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default App;
